import { useState } from 'react';
import { Confirm } from '@mayao/mayao-ui/core/Confirm';
import { Button, BUTTON_TEXT, ButtonType } from '@mayao/mayao-ui/core/Button';

const Example = () => {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <>
      <Button btnType={ButtonType.Success} onClick={() => setIsOpen(true)}>
        Открыть Confirm
      </Button>

      <Confirm
        isOpen={isOpen}
        title="Подтверждение"
        message="Вы уверены, что хотите продолжить?"
        onClose={() => setIsOpen(false)}
        onConfirm={() => {
          alert('Подтверждено!');
          setIsOpen(false);
        }}
        confirmButtonText={BUTTON_TEXT.confirm}
        cancelButtonText={BUTTON_TEXT.cancel}
        showCancelButton
      />
    </>
  );
};

import { useState } from 'react';
import { Button } from '@mayao/mayao-ui/core/Button';
import { DatePicker } from '@mayao/mayao-ui/core/DatePicker';

const Example = () => {
  const [date, setDate] = useState(new Date());
  const [isOpen, setIsOpen] = useState(false);

  return (
    <>
      <Button onClick={() => setIsOpen(true)}>Открыть календарь</Button>

      <DatePicker
        isOpen={isOpen}
        selectedDate={date}
        onClose={() => setIsOpen(false)}
        onDatePickerChange={(newDate) => {
          setDate(newDate);
          setIsOpen(false);
        }}
      />
    </>
  );
};

