import { useState } from 'react';
import { Pagination } from '@mayao/mayao-ui/core/Pagination';

const Example = () => {
  const [page, setPage] = useState(2);
  const [pageSize, setPageSize] = useState(10);
  const totalPages = 36;
  const totalElements = 354;

  return (
    <div>
      <Pagination
        page={page}
        totalPages={totalPages}
        totalElements={totalElements}
        pageSize={pageSize}
        onChange={setPage}
        onPageSizeChange={setPageSize}
        pageSizeOptions={[10, 25, 50]}
        siblingCount={1}
        boundaryCount={1}
      />
      <div>
        Текущая страница: <b>{page + 1}</b>, Размер страницы: <b>{pageSize}</b>
      </div>
    </div>
  );
};

import { useState } from 'react';
import Calendar from '@/assets/icons/bc_calendarV2.svg?react';
import { DateTimePickerV2 } from '@mayao/mayao-ui/core/DateTimePickerV2';

const Example = () => {
  const [value, setValue] = useState<Date | null>(null);

  return (
    <div className="mr-3.5 flex flex-col items-start gap-2">
      <DateTimePickerV2
        value={value}
        onChange={setValue}
        iconSize={24}
        placeholder="ДД.ММ.ГГГГ ЧЧ:ММ"
        format="datetime"
        icon={Calendar}
      />
      <div className="text-muted-foreground text-xs">
        <b>Текущее значение:</b>{' '}
        {value ? `${value.toLocaleDateString()} ${value.toTimeString().slice(0, 5)}` : '(не выбрано)'}
      </div>
    </div>
  );
};

